(self.webpackChunkvuepress_blog=self.webpackChunkvuepress_blog||[]).push([[1609],{8183:(n,a,s)=>{"use strict";s.r(a),s.d(a,{data:()=>t});const t={key:"v-1424b29d",path:"/pages/css/dev-experience/",title:"",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:3,title:"font-display",slug:"font-display",children:[]}],filePathRelative:"pages/css/dev-experience/README.md",git:{updatedTime:1716447612e3,contributors:[{name:"COOKIES-LGL",email:"1344714332@qq.com",commits:1}]}}},2046:(n,a,s)=>{"use strict";s.r(a),s.d(a,{default:()=>e});const t=(0,s(6252).uE)('<h3 id="font-display"><a class="header-anchor" href="#font-display">#</a> font-display</h3><h4 id="font-face-后文本的渲染过程"><a class="header-anchor" href="#font-face-后文本的渲染过程">#</a> @font-face 后文本的渲染过程</h4><ul><li>下载 web font</li><li>在下载期间先用备选字体渲染</li><li>web font 字体下载完成后使用该字体替换 实际这只是 @font-face 渲染方式的一种，而且不是默认的，@font-face 由 font-display属性决定 web font 在下载时间和可用时间是如何展示的 在字体下载比较慢的情况下</li><li>如果认为字体切换带来的闪烁不是问题，可以设置 font-display:swap;提前渲染文本</li><li>如果认为不一定要保障使用 web font 来渲染，那么无疑 font-display:optional;是最优选</li></ul><h4 id="提前加载-web-font"><a class="header-anchor" href="#提前加载-web-font">#</a> 提前加载 web font</h4><p>令人意外的是浏览器解析到 @font-face 声明时候并不会下载对应的字体，只有解析到使用了该 font-face 中定义字体的页面元素时，才会下载对应的字体这也就意味着把 @font-face 声明写在页面顶部是没有作用的，可以使用 preconnect 或者 preload 提前让浏览器提前建连和下载字体文件，尤其是在页面应用了流式渲染时候有奇效</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>link</span> <span class="token attr-name">rel</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>preconnect<span class="token punctuation">&quot;</span></span> <span class="token attr-name">href</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>https://fonts.gstatic.com<span class="token punctuation">&quot;</span></span> <span class="token attr-name">crossorigin</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>link</span> <span class="token attr-name">rel</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>preload<span class="token punctuation">&quot;</span></span> <span class="token attr-name">href</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>https://fonts.gstatic.com/s/roboto/v30/KFOkCnqEu92Fr1MmgVxFIzIXKMnyrYk.woff2<span class="token punctuation">&quot;</span></span> <span class="token attr-name">as</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>font<span class="token punctuation">&quot;</span></span> <span class="token attr-name">type</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>font/woff2<span class="token punctuation">&quot;</span></span> <span class="token attr-name">crossorigin</span><span class="token punctuation">&gt;</span></span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h4 id="unicode-range-子集化缩减-web-font-体积"><a class="header-anchor" href="#unicode-range-子集化缩减-web-font-体积">#</a> unicode-range 子集化缩减 web font 体积</h4><p>在 @font-face 内部可以使用 unicode-range 定义字体应用到的 Unicode 字符范围。这样可以将字体文件拆分成多个，当字符在定义的范围内时，浏览器才会下载并使用对应的字体文件</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token atrule"><span class="token rule">@font-face</span></span> <span class="token punctuation">{</span>\n  <span class="token property">font-family</span><span class="token punctuation">:</span> <span class="token string">&#39;MyFont&#39;</span><span class="token punctuation">;</span>\n  <span class="token property">src</span><span class="token punctuation">:</span> <span class="token url"><span class="token function">url</span><span class="token punctuation">(</span><span class="token string url">&#39;myfont.woff2&#39;</span><span class="token punctuation">)</span></span> <span class="token function">format</span><span class="token punctuation">(</span><span class="token string">&#39;woff2&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n  <span class="token property">unicode-range</span><span class="token punctuation">:</span> U+00-FF<span class="token punctuation">;</span> <span class="token comment">/* 基本拉丁字母及扩展 */</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div>',9),e={render:function(n,a){return t}}}}]);